{{
  (() => {
    const item = Custom1.model.itemSeleccionado;
    const cant = Number(inp_cantidad_compra.text || 0);
    const estID = sel_estacion.selectedOptionValue;

    // 🛰️ Capturamos la etiqueta traducida del motor
    const etiqueta = Motor_i18n.t('Tienda_Principal', 'lbl_flete');

    if (!item || cant <= 0 || !estID) return etiqueta + ": 0 ISK";

    const est = Leer_Estaciones.data.find(e => e.id_estacion == estID);
    const saltos = Number(est?.saltos_desde_origen || 0);

    // Precio base para el cálculo del 0.1% de flete
    const precioVenta = Number(item.mejor_precio || item.precio_isk || 0);
    const subtotal = cant * precioVenta;

    // 🧮 Fórmula: Base (2.5M) + Distancia (800k/salto) + Volumen (180/m3) + Valor (0.1%)
    const flete = 2500000 + (saltos * 800000) + (cant * Number(item.volumen_unitario || 0) * 180) + (subtotal * 0.001);

    // Retornamos la etiqueta y el valor formateado
    return etiqueta + ": " + flete.toLocaleString('en-US') + " ISK";
  })()
}}
